import type { CalcConfig } from './types'
import { BOLSA_FAMILIA_2026, BPC_2026, VALE_GAS_2026, SALARIO_MINIMO_2026 } from '@/lib/calculos/tabelas-vigentes'
import { calcularINSS } from '@/lib/calculos/trabalhista'
