const DIS_SOCIAL = 'Valores estimados conforme regras vigentes em 2026. Consulte o CRAS ou gov.br para confirmação.'

function calcBF(membros: number, renda: number, c06: number, c718: number, gest: number, nutr: number): number {
  const rpc = renda / membros
  const elegivel = rpc <= BOLSA_FAMILIA_2026.renda_maxima_per_capita
  if (!elegivel) return 0
  return BOLSA_FAMILIA_2026.base + c06 * BOLSA_FAMILIA_2026.adicional_primeira_infancia + (c718 + gest + nutr) * BOLSA_FAMILIA_2026.adicional_variavel
}

